B.PO=new A.aF("gen_al_expl_5","economic_law","\uc57d\uad00 \uba85\uc2dc\xb7\uc124\uba85\uc758\ubb34",null,'\uc57d\uad00\uc758 \uaddc\uc81c\uc5d0 \uad00\ud55c \ubc95\ub960\uc0c1 "\uc124\uba85\uc758\ubb34"\uc758 \ub300\uc0c1\uc774 \ub418\ub294 "\uc911\uc694\ud55c \ub0b4\uc6a9"\uc5d0 \ud574\ub2f9\ud558\uc9c0 \uc54a\ub294 \uac83\uc740?',B.FI,3,'\ud310\ub840\uc0c1 \uc124\uba85\uc758\ubb34\uc758 \ub300\uc0c1\uc774 \ub418\ub294 "\uc911\uc694\ud55c \ub0b4\uc6a9"\uc740 \uace0\uac1d\uc758 \uad8c\ub9ac\xb7\uc758\ubb34\uc5d0 \uc911\ub300\ud55c \uc601\ud5a5\uc744 \ubbf8\uce58\ub294 \uc0ac\ud56d, \uc989 \uace0\uac1d\uc758 \uad8c\ub9ac\ub97c \uc81c\ud55c\ud558\uac70\ub098 \uc0c8\ub85c\uc6b4 \uc758\ubb34\ub97c \ubd80\uacfc\ud558\ub294 \uc870\ud56d, \ud574\uc9c0\xb7\ud574\uc81c \uc0ac\uc720, \ube44\uc6a9\ubd80\ub2f4 \uc870\ud56d \ub4f1\uc744 \ub9d0\ud55c\ub2e4. \ubc18\uba74 \ubc95\ub839\uc5d0 \uc774\ubbf8 \uc815\ud574\uc838 \uc788\uc5b4 \uc0ac\uc5c5\uc790\uac00 \uacc4\uc57d\uc5d0 \ubc18\uc601\ud588\uc744 \ubfd0\uc778 \ub0b4\uc6a9\uc740 \uace0\uac1d\uc774 \uc774\ubbf8 \uc54c\uace0 \uc788\uc5c8\uac70\ub098 \uc54c \uc218 \uc788\uc5c8\ub358 \uac83\uc73c\ub85c \ucde8\uae09\ub418\uc5b4 \ubcc4\ub3c4\uc758 \uc124\uba85\uc758\ubb34 \ub300\uc0c1\uc5d0\uc11c \uc81c\uc678\ub418\ub294 \uacbd\uc6b0\uac00 \ub9ce\ub2e4.',B.HE,B.Hh,null)
