B.Pt=new A.aF("gen_al_expl_6","economic_law","\uc57d\uad00 \uba85\uc2dc\xb7\uc124\uba85\uc758\ubb34",null,"\uc57d\uad00\uc758 \uaddc\uc81c\uc5d0 \uad00\ud55c \ubc95\ub960\uc0c1 \uc124\uba85\uc758\ubb34\uac00 \uba74\uc81c\ub418\ub294 \uacbd\uc6b0\ub85c \uc633\uc740 \uac83\uc744 \ubaa8\ub450 \uace0\ub978 \uac83\uc740?\n\n\u3131. \uacc4\uc57d\uc758 \uc131\uc9c8\uc0c1 \uc124\uba85\uc774 \ud604\uc800\ud788 \uace4\ub780\ud55c \uacbd\uc6b0\n\u3134. \uace0\uac1d\uc774\ub098 \uadf8 \ub300\ub9ac\uc778\uc774 \uadf8 \uc870\ud56d\uc758 \ub0b4\uc6a9\uc744 \ubcc4\ub3c4\ub85c \uc124\uba85\ud558\uc9c0 \uc54a\uc544\ub3c4 \ucda9\ubd84\ud788 \uc608\uc0c1\ud560 \uc218 \uc788\uc5c8\ub358 \uacbd\uc6b0\n\u3137. \uc0ac\uc5c5\uc790\uac00 \ub2e8\uc21c\ud788 \ubc14\uc058\ub2e4\ub294 \uc774\uc720\ub85c \uc124\uba85\uc744 \uc0dd\ub7b5\ud55c \uacbd\uc6b0",B.Ip,2,"\ud310\ub840\ub294 \uacc4\uc57d\uc758 \uc131\uc9c8\uc0c1 \uc124\uba85\uc774 \ud604\uc800\ud788 \uace4\ub780\ud55c \uacbd\uc6b0(\u3131) \uc678\uc5d0\ub3c4, \uc774\ubbf8 \ubc95\ub839\uc5d0 \uaddc\uc815\ub418\uc5b4 \uc788\uac70\ub098 \uac70\ub798\uacc4\uc5d0\uc11c \uc77c\ubc18\uc801\uc774\uace0 \uacf5\ud1b5\ub41c \uac83\uc774\uc5b4\uc11c \uace0\uac1d\uc774 \ubcc4\ub3c4 \uc124\uba85 \uc5c6\uc774\ub3c4 \ucda9\ubd84\ud788 \uc608\uc0c1\ud560 \uc218 \uc788\uc5c8\ub358 \uc0ac\ud56d(\u3134)\uc5d0 \ub300\ud574\uc11c\ub294 \uc124\uba85\uc758\ubb34\uc758 \uc608\uc678\ub97c \uc778\uc815\ud55c\ub2e4. \uadf8\ub7ec\ub098 \uc0ac\uc5c5\uc790\uc758 \ub2e8\uc21c\ud55c \uc5c5\ubb34 \ud3b8\uc758\ub098 \uc2dc\uac04 \ubd80\uc871(\u3137)\uc740 \uc124\uba85\uc758\ubb34 \uba74\uc81c \uc0ac\uc720\ub85c \uc778\uc815\ub418\uc9c0 \uc54a\ub294\ub2e4.",B.Km,B.Io,null)
B.G_=s(["\uacc4\uc57d \uc804\uccb4\uac00 \ucc98\uc74c\ubd80\ud130 \ubb34\ud6a8\ub85c \ub41c\ub2e4","\uc0ac\uc5c5\uc790\ub294 \ud574\ub2f9 \uc57d\uad00 \uc870\ud56d\uc744 \uacc4\uc57d\uc758 \ub0b4\uc6a9\uc73c\ub85c \uc8fc\uc7a5\ud560 \uc218 \uc5c6\ub2e4","\uace0\uac1d\uc774 \uc190\ud574\ubc30\uc0c1\uc744 \uccad\uad6c\ud560 \uc218 \uc788\uc744 \ubfd0 \uc870\ud56d\uc758 \ud6a8\ub825\uc5d0\ub294 \uc601\ud5a5\uc774 \uc5c6\ub2e4","\uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\uc758 \uc2dc\uc815\uba85\ub839\uc774 \uc788\uc5b4\uc57c\ub9cc \uc870\ud56d\uc758 \ud6a8\ub825\uc774 \ubd80\uc815\ub41c\ub2e4","\uace0\uac1d\uc774 \ubcc4\ub3c4\ub85c \ucde8\uc18c\uad8c\uc744 \ud589\uc0ac\ud574\uc57c\ub9cc \uc870\ud56d\uc758 \ud6a8\ub825\uc774 \ubd80\uc815\ub41c\ub2e4"],t.s)
B.Hz=s(['\ud574\ub2f9 \uc57d\uad00\uc744 \uacc4\uc57d\uc758 \ub0b4\uc6a9\uc73c\ub85c "\uc8fc\uc7a5\ud560 \uc218 \uc5c6\ub2e4"'],t.s)
