B.O0=new A.eK("economic_law","\uacbd\uc81c\ubc95","\uc2dc\uc7a5\uc9c0\ubc30\uc801\uc0ac\uc5c5\uc790\uc758 \ucd94\uc815\uc5d0\ub294 \ub9e4\ucd9c\uc561\ubfd0 \uc544\ub2c8\ub77c \uc2dc\uc7a5\uc810\uc720\uc728\ub3c4 \ud568\uaed8 \uace0\ub824\ub41c\ub2e4.",!0,"\uacf5\uc815\uac70\ub798\ubc95\uc0c1 \uc2dc\uc7a5\uc9c0\ubc30\uc801\uc0ac\uc5c5\uc790 \ucd94\uc815\uc740 \uc2dc\uc7a5\uc810\uc720\uc728\uc744 \uae30\uc900\uc73c\ub85c \ud558\uba70, 1\uac1c \uc0ac\uc5c5\uc790 50% \uc774\uc0c1 \ub610\ub294 3\uac1c \uc774\ud558 \uc0ac\uc5c5\uc790 \ud569\uacc4 75% \uc774\uc0c1\uc778 \uacbd\uc6b0 \ub4f1\uc774 \ud574\ub2f9\ub429\ub2c8\ub2e4.")
